# solution.py
"""Team Collaboration Manager - complete implementation."""

import copy
import csv
import enum
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Any, Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(enum.Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(enum.Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(enum.Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment] = field(default_factory=list)
    created_at: datetime = field(default_factory=datetime.now)
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Store
# ---------------------------------------------------------------------------
class Store:
    """Simple dict-backed store that shares a lock with the manager."""

    def __init__(self, lock: threading.RLock):
        self._lock = lock
        self._data: Dict[int, Any] = {}

    def get(self, key: int):
        return self._data.get(key)

    def put(self, key: int, value: Any):
        self._data[key] = value

    def delete(self, key: int):
        self._data.pop(key, None)

    def values(self):
        return list(self._data.values())

    def __contains__(self, key: int):
        return key in self._data


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._now = now if now is not None else (lambda: datetime.now())
        self._lock = threading.RLock()
        self._next_id = 1

        self.users = Store(self._lock)
        self.projects = Store(self._lock)
        self.tasks = Store(self._lock)
        self.messages = Store(self._lock)
        self.performance = Store(self._lock)
        self.reports = Store(self._lock)

        # indexes
        self._username_index: Dict[str, int] = {}
        self._email_index: Dict[str, int] = {}
        self._project_tasks: Dict[int, List[int]] = {}
        self._assignee_tasks: Dict[int, set] = {}
        self._project_messages: Dict[int, List[int]] = {}
        self._task_messages: Dict[int, List[int]] = {}
        self._ratee_ratings: Dict[int, List[int]] = {}

    def _gen_id(self) -> int:
        uid = self._next_id
        self._next_id += 1
        return uid

    # -- User methods -------------------------------------------------------

    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        with self._lock:
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")
            stripped = username.strip()
            if not stripped:
                raise ValidationError("username must not be empty")
            if not email:
                raise ValidationError("email must not be empty")
            if "@" not in email:
                raise ValidationError("email must contain @")
            if stripped in self._username_index:
                raise DuplicateError("username already taken")
            if email in self._email_index:
                raise DuplicateError("email already taken")
            uid = self._gen_id()
            user = User(
                id=uid,
                username=stripped,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.put(uid, user)
            self._username_index[stripped] = uid
            self._email_index[email] = uid
            return copy.deepcopy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            user = self.users.get(user_id)
            if user is None:
                raise NotFoundError("user not found")
            return copy.deepcopy(user)

    def list_users(self) -> List[User]:
        with self._lock:
            users = sorted(self.users.values(), key=lambda u: u.id)
            return [copy.deepcopy(u) for u in users]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self.users.get(user_id)
            if user is None:
                raise NotFoundError("user not found")
            if username is not None:
                stripped = username.strip()
                if not stripped:
                    raise ValidationError("username must not be empty")
                if (
                    stripped in self._username_index
                    and self._username_index[stripped] != user_id
                ):
                    raise DuplicateError("username already taken")
                del self._username_index[user.username]
                user.username = stripped
                self._username_index[stripped] = user_id
            if email is not None:
                if not email:
                    raise ValidationError("email must not be empty")
                if "@" not in email:
                    raise ValidationError("email must contain @")
                if (
                    email in self._email_index
                    and self._email_index[email] != user_id
                ):
                    raise DuplicateError("email already taken")
                del self._email_index[user.email]
                user.email = email
                self._email_index[email] = user_id
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self.users.get(user_id)
            if user is None:
                raise NotFoundError("user not found")
            # check project ownership
            for proj in self.projects.values():
                if proj.owner_id == user_id:
                    raise ConflictError("user owns a project")
            # check open tasks
            task_ids = self._assignee_tasks.get(user_id, set())
            for tid in task_ids:
                task = self.tasks.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks")
            # remove
            del self._username_index[user.username]
            del self._email_index[user.email]
            self.users.delete(user_id)
            self._assignee_tasks.pop(user_id, None)

    # -- Project methods ----------------------------------------------------

    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            if self.users.get(owner_id) is None:
                raise NotFoundError("owner not found")
            if not name or not name.strip():
                raise ValidationError("name must not be empty")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")
            pid = self._gen_id()
            project = Project(
                id=pid,
                name=name,
                description=description,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
            )
            self.projects.put(pid, project)
            self._project_tasks[pid] = []
            self._project_messages[pid] = []
            return copy.deepcopy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            project = self.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            return copy.deepcopy(project)

    def list_projects(self) -> List[Project]:
        with self._lock:
            projects = sorted(self.projects.values(), key=lambda p: p.id)
            return [copy.deepcopy(p) for p in projects]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        description: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
    ) -> Project:
        with self._lock:
            project = self.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            if name is not None:
                if not name or not name.strip():
                    raise ValidationError("name must not be empty")
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if project.end_date < project.start_date:
                raise ValidationError("end_date must not be before start_date")
            return copy.deepcopy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            project = self.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            # cascade tasks
            task_ids = list(self._project_tasks.get(project_id, []))
            for tid in task_ids:
                task = self.tasks.get(tid)
                if task is not None:
                    if task.assignee_id is not None:
                        s = self._assignee_tasks.get(task.assignee_id)
                        if s is not None:
                            s.discard(tid)
                    # cascade task messages
                    tmsg_ids = list(self._task_messages.get(tid, []))
                    for mid in tmsg_ids:
                        self.messages.delete(mid)
                    self._task_messages.pop(tid, None)
                    self.tasks.delete(tid)
            self._project_tasks.pop(project_id, None)
            # cascade project messages
            pmsg_ids = list(self._project_messages.get(project_id, []))
            for mid in pmsg_ids:
                self.messages.delete(mid)
            self._project_messages.pop(project_id, None)
            self.projects.delete(project_id)

    # -- Task methods -------------------------------------------------------

    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            project = self.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            if assignee_id is not None and self.users.get(assignee_id) is None:
                raise NotFoundError("assignee not found")
            if not title or not title.strip():
                raise ValidationError("title must not be empty")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError(
                    "deadline must not be before project start"
                )
            tid = self._gen_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks.put(tid, task)
            self._project_tasks.setdefault(project_id, []).append(tid)
            if assignee_id is not None:
                self._assignee_tasks.setdefault(assignee_id, set()).add(tid)
            return copy.deepcopy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            task = self.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            return copy.deepcopy(task)

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            if self.projects.get(project_id) is None:
                raise NotFoundError("project not found")
            task_ids = self._project_tasks.get(project_id, [])
            tasks = []
            for tid in task_ids:
                task = self.tasks.get(tid)
                if task is not None:
                    tasks.append(copy.deepcopy(task))
            tasks.sort(key=lambda t: t.id)
            return tasks

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            if self.users.get(assignee_id) is None:
                raise NotFoundError("user not found")
            task_ids = self._assignee_tasks.get(assignee_id, set())
            tasks = []
            for tid in task_ids:
                task = self.tasks.get(tid)
                if task is not None:
                    tasks.append(copy.deepcopy(task))
            tasks.sort(key=lambda t: t.id)
            return tasks

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if self.users.get(assignee_id) is None:
                raise NotFoundError("assignee not found")
            old = task.assignee_id
            if old is not None:
                s = self._assignee_tasks.get(old)
                if s is not None:
                    s.discard(task_id)
            task.assignee_id = assignee_id
            self._assignee_tasks.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            old = task.assignee_id
            if old is not None:
                s = self._assignee_tasks.get(old)
                if s is not None:
                    s.discard(task_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if deadline is not None:
                project = self.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not be before project start"
                    )
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            task = self.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # -- Message methods ----------------------------------------------------

    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
        parent_id: Optional[int] = None,
    ) -> Message:
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if self.users.get(author_id) is None:
                raise NotFoundError("author not found")
            if project_id is not None and self.projects.get(project_id) is None:
                raise NotFoundError("project not found")
            if task_id is not None and self.tasks.get(task_id) is None:
                raise NotFoundError("task not found")
            if parent_id is not None and self.messages.get(parent_id) is None:
                raise NotFoundError("parent message not found")

            att_list: List[Attachment] = []
            if attachments:
                now = self._now()
                for fname, data in attachments:
                    att_list.append(
                        Attachment(
                            filename=fname,
                            size=len(data),
                            uploaded_by=author_id,
                            uploaded_at=now,
                        )
                    )

            if not body and not att_list:
                raise ValidationError(
                    "body must not be empty when no attachments"
                )

            mid = self._gen_id()
            msg = Message(
                id=mid,
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=att_list,
                created_at=self._now(),
                edited_at=None,
            )
            self.messages.put(mid, msg)
            if project_id is not None:
                self._project_messages.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self._task_messages.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def edit_message(
        self, message_id: int, editor_id: int, new_body: str
    ) -> Message:
        with self._lock:
            msg = self.messages.get(message_id)
            if msg is None:
                raise NotFoundError("message not found")
            if msg.author_id != editor_id:
                raise AuthorizationError("not the author")
            if not new_body:
                raise ValidationError("body must not be empty")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(
        self, message_id: int, user_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            msg = self.messages.get(message_id)
            if msg is None:
                raise NotFoundError("message not found")
            if msg.author_id != user_id:
                raise AuthorizationError("not the author")
            if not filename:
                raise ValidationError("filename must not be empty")
            att = Attachment(
                filename=filename,
                size=len(data),
                uploaded_by=user_id,
                uploaded_at=self._now(),
            )
            msg.attachments.append(att)
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            if self.projects.get(project_id) is None:
                raise NotFoundError("project not found")
            msg_ids = self._project_messages.get(project_id, [])
            msgs = []
            for mid in msg_ids:
                msg = self.messages.get(mid)
                if msg is not None:
                    msgs.append(copy.deepcopy(msg))
            msgs.sort(key=lambda m: m.id)
            return msgs

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            if self.tasks.get(task_id) is None:
                raise NotFoundError("task not found")
            msg_ids = self._task_messages.get(task_id, [])
            msgs = []
            for mid in msg_ids:
                msg = self.messages.get(mid)
                if msg is not None:
                    msgs.append(copy.deepcopy(msg))
            msgs.sort(key=lambda m: m.id)
            return msgs

    def delete_message(self, message_id: int, user_id: int) -> None:
        with self._lock:
            msg = self.messages.get(message_id)
            if msg is None:
                raise NotFoundError("message not found")
            if msg.author_id != user_id:
                raise AuthorizationError("not the author")
            if msg.project_id is not None:
                lst = self._project_messages.get(msg.project_id)
                if lst is not None:
                    try:
                        lst.remove(message_id)
                    except ValueError:
                        pass
            if msg.task_id is not None:
                lst = self._task_messages.get(msg.task_id)
                if lst is not None:
                    try:
                        lst.remove(message_id)
                    except ValueError:
                        pass
            self.messages.delete(message_id)

    # -- Performance methods ------------------------------------------------

    def _get_assigned_tasks(self, user_id: int) -> List[Task]:
        task_ids = self._assignee_tasks.get(user_id, set())
        tasks = []
        for tid in task_ids:
            task = self.tasks.get(tid)
            if task is not None:
                tasks.append(task)
        return tasks

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            if self.users.get(user_id) is None:
                raise NotFoundError("user not found")
            tasks = self._get_assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            if self.users.get(user_id) is None:
                raise NotFoundError("user not found")
            tasks = self._get_assigned_tasks(user_id)
            completed = [
                t
                for t in tasks
                if t.status == TaskStatus.COMPLETED
                and t.completed_at is not None
                and t.started_at is not None
            ]
            if not completed:
                return None
            total = sum(
                (t.completed_at - t.started_at).total_seconds()
                for t in completed
            )
            return total / len(completed)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if self.users.get(rater_id) is None:
                raise NotFoundError("rater not found")
            if self.users.get(ratee_id) is None:
                raise NotFoundError("ratee not found")
            if task_id is not None and self.tasks.get(task_id) is None:
                raise NotFoundError("task not found")
            rid = self._gen_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.put(rid, rating)
            self._ratee_ratings.setdefault(ratee_id, []).append(rid)
            return copy.deepcopy(rating)

    def _get_ratings_for_user(self, user_id: int) -> List[Rating]:
        result: List[Rating] = []
        for rid in self._ratee_ratings.get(user_id, []):
            r = self.performance.get(rid)
            if r is not None:
                result.append(r)
        return result

    def get_ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            if self.users.get(user_id) is None:
                raise NotFoundError("user not found")
            ratings = self._get_ratings_for_user(user_id)
            if not ratings:
                return {"count": 0, "average": 0.0, "ratings": []}
            avg = sum(r.score for r in ratings) / len(ratings)
            return {
                "count": len(ratings),
                "average": avg,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            if self.users.get(user_id) is None:
                raise NotFoundError("user not found")
            tasks = self._get_assigned_tasks(user_id)
            total = len(tasks)
            completed = in_progress = not_started = 0
            done_times: List[float] = []
            for t in tasks:
                s = t.status
                if s == TaskStatus.COMPLETED:
                    completed += 1
                    if t.completed_at is not None and t.started_at is not None:
                        done_times.append(
                            (t.completed_at - t.started_at).total_seconds()
                        )
                elif s == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                elif s == TaskStatus.NOT_STARTED:
                    not_started += 1
            comp_rate = completed / total if total else 0.0
            avg_time = (
                sum(done_times) / len(done_times) if done_times else None
            )
            ratings = self._get_ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_avg = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": comp_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_avg,
            }

    # -- Report methods -----------------------------------------------------

    def project_progress_report(self, project_id: int) -> dict:
        with self._lock:
            if self.projects.get(project_id) is None:
                raise NotFoundError("project not found")
            task_ids = self._project_tasks.get(project_id, [])
            tasks = []
            for tid in task_ids:
                t = self.tasks.get(tid)
                if t is not None:
                    tasks.append(t)
            total = len(tasks)
            status_counts = {s.value: 0 for s in TaskStatus}
            now = self._now()
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            for t in tasks:
                status_counts[t.status.value] += 1
                if (
                    t.deadline is not None
                    and now > t.deadline
                    and t.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if t.assignee_id is not None:
                    if t.assignee_id not in per_assignee:
                        per_assignee[t.assignee_id] = {
                            "total_tasks": 0,
                            "completed_tasks": 0,
                            "in_progress_tasks": 0,
                            "not_started_tasks": 0,
                        }
                    pa = per_assignee[t.assignee_id]
                    pa["total_tasks"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        pa["completed_tasks"] += 1
                    elif t.status == TaskStatus.IN_PROGRESS:
                        pa["in_progress_tasks"] += 1
                    else:
                        pa["not_started_tasks"] += 1
            comp_rate = (
                status_counts[TaskStatus.COMPLETED.value] / total
                if total
                else 0.0
            )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": comp_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> dict:
        with self._lock:
            if project_id is not None:
                if self.projects.get(project_id) is None:
                    raise NotFoundError("project not found")
            # gather tasks in scope
            if project_id is not None:
                task_ids = self._project_tasks.get(project_id, [])
                tasks_in_scope = []
                for tid in task_ids:
                    t = self.tasks.get(tid)
                    if t is not None:
                        tasks_in_scope.append(t)
            else:
                tasks_in_scope = list(self.tasks.values())

            assignee_map: Dict[int, List[Task]] = {}
            for t in tasks_in_scope:
                if t.assignee_id is not None:
                    assignee_map.setdefault(t.assignee_id, []).append(t)

            rows = []
            for uid in sorted(assignee_map.keys()):
                user_tasks = assignee_map[uid]
                total = len(user_tasks)
                completed = sum(
                    1
                    for t in user_tasks
                    if t.status == TaskStatus.COMPLETED
                )
                comp_rate = completed / total if total else 0.0
                # avg completion time
                done = [
                    t
                    for t in user_tasks
                    if t.status == TaskStatus.COMPLETED
                    and t.completed_at is not None
                    and t.started_at is not None
                ]
                avg_time = (
                    sum(
                        (t.completed_at - t.started_at).total_seconds()
                        for t in done
                    )
                    / len(done)
                    if done
                    else None
                )
                ratings = self._get_ratings_for_user(uid)
                rating_count = len(ratings)
                rating_avg = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                user = self.users.get(uid)
                uname = user.username if user else "unknown"
                rows.append(
                    {
                        "user_id": uid,
                        "username": uname,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": comp_rate,
                        "average_completion_time": avg_time,
                        "rating_average": rating_avg,
                        "rating_count": rating_count,
                    }
                )
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> dict:
        with self._lock:
            if self.users.get(user_id) is None:
                raise NotFoundError("user not found")
            tasks = self._get_assigned_tasks(user_id)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            task_rows = []
            for t in sorted(tasks, key=lambda x: x.id):
                task_rows.append(
                    {
                        "task_id": t.id,
                        "title": t.title,
                        "status": t.status.value,
                        "project_id": t.project_id,
                    }
                )
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": completed,
                "tasks": task_rows,
            }

    def export_report(self, report: Any, fmt: ReportFormat) -> Any:
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("format must be a ReportFormat instance")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        elif fmt == ReportFormat.PDF:
            return self._export_pdf(report)

    def _export_csv(self, report: dict) -> str:
        buf = io.StringIO()
        writer = csv.writer(buf)
        rt = report.get("report_type", "")
        if rt == ReportType.TEAM_PERFORMANCE.value:
            rows = report.get("rows", [])
            if rows:
                header = list(rows[0].keys())
                writer.writerow(header)
                for row in rows:
                    writer.writerow([row.get(k, "") for k in header])
            else:
                writer.writerow(["report_type"])
                writer.writerow([rt])
        elif rt == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(
                [
                    "report_type",
                    "total_tasks",
                    "completion_rate",
                    "overdue_tasks",
                ]
            )
            writer.writerow(
                [
                    rt,
                    report.get("total_tasks", 0),
                    report.get("completion_rate", 0.0),
                    report.get("overdue_tasks", 0),
                ]
            )
        elif rt == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(
                ["user_id", "total_tasks", "completed_tasks"]
            )
            writer.writerow(
                [
                    report.get("user_id", ""),
                    report.get("total_tasks", 0),
                    report.get("completed_tasks", 0),
                ]
            )
        else:
            keys = list(report.keys())
            writer.writerow(keys)
            writer.writerow([report.get(k, "") for k in keys])
        return buf.getvalue()

